return-response.set-body:
@{
                string clientCertHeader = context.Request.Headers.GetValueOrDefault("X-Client-Certificate");
                X509Certificate2 certificate = null;

                if (!string.IsNullOrWhiteSpace(clientCertHeader))
                {
                    // Decode the header value (e.g. replace %20 with a whitespace) and remove the begin and end certificate markers.
                    // The result is the base64 encoded certificate in X.509 (.cer) format without the private key.
                    var pem = System.Net.WebUtility.UrlDecode(clientCertHeader)
                                                   .Replace("-----BEGIN CERTIFICATE-----", "")
                                                   .Replace("-----END CERTIFICATE-----", "");

                    certificate = new X509Certificate2(Convert.FromBase64String(pem));
                }

                return JsonConvert.SerializeObject(new
                {
                    certificate = new
                    {
                        details = certificate?.ToString(),
                        header = clientCertHeader
                    },
                    request = new {
                        headers = string.Join(",", context.Request.Headers.Keys.OrderBy(s => s))
                    }
                });
            }
